# 特征欧氏距离相似度匹配引擎
def find_closest_city_advice(input_data, is_heavy):
    target_type = "典型重化工业主导城市" if is_heavy else "泛基准与综合型城市"
    pool = df[df["类型"] == target_type]

    best_city = None
    min_dist = float('inf')

    # 提取用于比对的核心特征，并进行极差归一化预处理以防量纲失真
    features = ["长途光缆", "高质量外资", "IT人才密度", "基准碳排"]
    for idx, row in pool.iterrows():
        dist = 0
        for f in features:
            f_max = pool[f].max()
            f_min = pool[f].min()
            rng = f_max - f_min if f_max > f_min else 1.0
            diff = (input_data[f] - row[f]) / rng
            dist += diff ** 2

        if dist < min_dist:
            min_dist = dist
            best_city = row["城市"]

    clean_best_city = best_city.replace("河南省", "").replace("山西省", "").replace("山东省", "").replace("安徽省", "")
    return clean_best_city


# 报告提取引擎
def get_report(city_name, current_data, logic, module_key):
    # 提取纯净市名
    clean_name = city_name.replace("河南省", "").replace("山西省", "").replace("山东省", "").replace("安徽省", "")

    if clean_name in city_advice_db:
        return city_advice_db[clean_name][module_key]
    else:
        # 如果是外部录入城市，启动智能匹配
        is_heavy = True if logic == "偏向重化工业主导" else False
        mirror_city = find_closest_city_advice(current_data, is_heavy)

        # fallback到默认的同类型，防止一些跨省市不在字典内导致报错
        safe_city = mirror_city if mirror_city in city_advice_db else ("焦作市" if is_heavy else "郑州市")

        # 1. 获取匹配到的镜像城市的原始建议文本 (去掉了原有的 prefix 提示)
        base_text = city_advice_db[safe_city][module_key]

        # 2. 准备简称（例如把"平顶山市"变为"平顶山"，以防文案中有简称）
        short_safe_city = safe_city.replace("市", "")
        short_clean_name = clean_name.replace("市", "")

        # 3. 动态文本替换：将文案中的原城市名全部替换为用户输入的城市名
        custom_text = base_text.replace(safe_city, clean_name).replace(short_safe_city, short_clean_name)

        return custom_text


# 报告精美卡片渲染引擎 (新增)
def render_custom_report(text):
    # 如果包含建议部分，进行切割渲染
    if "【多部门协同决策指导建议】：" in text:
        analysis_part, advice_part = text.split("【多部门协同决策指导建议】：")

        # 1. 渲染上半部分：分析与推演过程
        clean_analysis = analysis_part.replace("【系统数据分析与推演过程】：", "").replace("【系统预警与研判过程】：", "").replace(
            "【反事实预测与SHAP归因过程】：", "").replace("【NSGA-III寻优与空间拓扑过程】：", "").strip()

        st.markdown(f"""
            <div style='background-color: #FAFAFA; border-left: 4px solid #1A3622; padding: 15px 20px; margin-top: 15px; margin-bottom: 25px; line-height: 1.8; font-size: 15px;'>
                <h4 style='color: #1A3622; margin-top: 0px; margin-bottom: 10px;'>📊 深度数据研判与推演过程</h4>
                {clean_analysis}
            </div>
        """, unsafe_allow_html=True)

        # 2. 渲染下半部分：具体建议（分块加框，大标题）
        st.markdown("<h3 style='color: #2C3539; font-weight: bold; margin-bottom: 15px;'>🎯 多部门协同决策指导方案</h3>",
                    unsafe_allow_html=True)

        advices = advice_part.strip().split("\n")
        for adv in advices:
            adv = adv.strip()
            if adv:
                # 自动识别“1. xxx局：”并拆分出大标题和内容
                if "：" in adv and (adv.startswith("1.") or adv.startswith("2.") or adv.startswith("3.")):
                    title, content = adv.split("：", 1)
                    st.markdown(f"""
                    <div style='background-color: #FFFFFF; border: 1px solid #E0E0E0; border-left: 5px solid #4DB8B3; padding: 20px; border-radius: 8px; margin-bottom: 15px; box-shadow: 0 4px 6px rgba(0,0,0,0.05);'>
                        <h4 style='color: #1A3622; font-size: 19px; margin-top: 0; margin-bottom: 12px; font-weight: bold;'>🏛️ {title}</h4>
                        <p style='margin-bottom: 0; color: #444444; line-height: 1.7; font-size: 15px;'>{content}</p>
                    </div>
                    """, unsafe_allow_html=True)
                else:
                    st.markdown(f"<p>{adv}</p>", unsafe_allow_html=True)
    else:
        st.markdown(f"<div class='analysis-box'>{text}</div>", unsafe_allow_html=True)

def normalize_to_100(val, col_name):
    min_val = df[col_name].min();
    max_val = df[col_name].max()
    if max_val == min_val: return 50
    return max(0, min((val - min_val) / (max_val - min_val) * 100, 100))


